const mexcPriceMap = {};
for (const item of $input.all()) {
  const t = item.json;
  if (typeof t.symbol === 'string' && t.symbol.endsWith('USDT')) {
    mexcPriceMap[t.symbol.slice(0, -4)] = parseFloat(t.price);
  }
}
return [{ json: { mexcPriceMap } }];

const mexcPriceMap = $('Build MEXC Price Map').first().json.mexcPriceMap;
const dbTokens = $input.all().map(item => item.json);

const result = [];
for (const token of dbTokens) {
  const { symbol, mint } = token;
  if (symbol && mint && mexcPriceMap[symbol] !== undefined) {
    result.push({ symbol, mint, mexcPrice: mexcPriceMap[symbol] });
  }
}
return result.map(t => ({ json: t }));

const mints = $input.all().map(t => t.json.mint);
const batches = [];
for (let i = 0; i < mints.length; i += 50) {
  batches.push(mints.slice(i, i + 50).join(','));
}
return batches.map(ids => ({ json: { mintIds: ids } }));

// Merge all Jupiter batch responses into one price map
const priceMap = {};
for (const item of $input.all()) {
  for (const [mint, data] of Object.entries(item.json)) {
    if (data && data.usdPrice != null) priceMap[mint] = parseFloat(data.usdPrice);
  }
}

// Compare against MEXC prices
const tokens = $('Find Common Tokens').all();
const spreads = [];
const timestamp = new Date().toISOString();

for (const item of tokens) {
  const { symbol, mint, mexcPrice } = item.json;
  const jupPrice = priceMap[mint];
  if (!jupPrice || !mexcPrice || isNaN(jupPrice) || isNaN(mexcPrice)) continue;

  const spreadPct = ((mexcPrice - jupPrice) / jupPrice) * 100;
  const absSpread = Math.abs(spreadPct);

  if (absSpread >= 5) {
    spreads.push({ symbol, mint, mexc_price: mexcPrice, jup_price: jupPrice,
      spread_pct: parseFloat(spreadPct.toFixed(4)),
      abs_spread_pct: parseFloat(absSpread.toFixed(4)),
      direction: spreadPct > 0 ? 'Buy JUP -> Sell MEXC' : 'Buy MEXC -> Sell JUP' });
  }
}

spreads.sort((a, b) => b.abs_spread_pct - a.abs_spread_pct);
return [{ json: { spreads, count: spreads.length, tokens_compared: tokens.length, timestamp } }];
